// Products.js (admin)
import React, { useEffect, useState } from 'react';
import { adminAPI, productAPI } from '../../utils/api';
import Spinner, { StarRating, StatusBadge } from '../../components/common/Spinner';
import toast from 'react-hot-toast';

export default function AdminProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    productAPI.getAll({ limit: 50 })
      .then(({ data }) => setProducts(data.products))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const approve = async (id) => {
    await adminAPI.approveProduct(id);
    setProducts(prev => prev.map(p => p._id === id ? { ...p, isApproved: true } : p));
    toast.success('Product approved!');
  };

  const remove = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    await productAPI.delete(id);
    setProducts(prev => prev.filter(p => p._id !== id));
    toast.success('Product deleted');
  };

  if (loading) return <Spinner />;

  return (
    <div>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '1.5rem' }}>Products ({products.length})</h1>
      <div className="card" style={{ overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: 'var(--gray-50)', borderBottom: '2px solid var(--gray-200)' }}>
              {['Product', 'Category', 'Price', 'Stock', 'Rating', 'Status', 'Actions'].map(h => (
                <th key={h} style={{ padding: '0.85rem 1rem', textAlign: 'left', fontSize: '0.78rem', fontWeight: 700, color: 'var(--gray-600)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {products.map(p => (
              <tr key={p._id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                <td style={{ padding: '0.85rem 1rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
                    <img src={p.images?.[0] || 'https://placehold.co/40x40/e8f5e9/2d6a4f?text=P'} alt={p.name} style={{ width: 40, height: 40, borderRadius: 8, objectFit: 'cover' }} />
                    <span style={{ fontSize: '0.875rem', fontWeight: 600, maxWidth: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{p.name}</span>
                  </div>
                </td>
                <td style={{ padding: '0.85rem 1rem', fontSize: '0.8rem' }}>{p.category?.name}</td>
                <td style={{ padding: '0.85rem 1rem', fontSize: '0.875rem', fontWeight: 600, color: 'var(--green-800)' }}>PKR {p.price?.toLocaleString()}</td>
                <td style={{ padding: '0.85rem 1rem', fontSize: '0.875rem' }}>
                  <span style={{ color: p.stock <= 5 ? '#dc2626' : p.stock <= 20 ? '#d97706' : 'var(--green-700)', fontWeight: 600 }}>{p.stock}</span>
                </td>
                <td style={{ padding: '0.85rem 1rem' }}><StarRating rating={p.ratings} /></td>
                <td style={{ padding: '0.85rem 1rem' }}><StatusBadge status={p.isApproved ? 'approved' : 'pending'} /></td>
                <td style={{ padding: '0.85rem 1rem' }}>
                  <div style={{ display: 'flex', gap: '0.4rem' }}>
                    {!p.isApproved && <button className="btn btn-secondary btn-sm" onClick={() => approve(p._id)}>✅ Approve</button>}
                    <button className="btn btn-danger btn-sm" onClick={() => remove(p._id)}>🗑</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
